     1→//! Comprehensive R comparison benchmarks
     2→//!
     3→//! This benchmark suite compares our Rust implementation against R's lm()
     4→//! to validate we're meeting our performance targets as defined in CLAUDE.md:
     5→//! - Linear Models: ≥2x faster than R's lm()
     6→
     7→use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
     8→use stats_models::Lm;
     9→use std::fs::File;
    10→use std::io::Write;
    11→use std::process::Command;
    12→use std::time::{SystemTime, UNIX_EPOCH};
    13→
    14→/// Generate test data for benchmarking
    15→fn generate_test_data(n_obs: usize, n_vars: usize) -> (Vec<f64>, Vec<f64>) {
    16→    // Create design matrix with intercept + random variables
    17→    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    18→    let mut y_data = Vec::with_capacity(n_obs);
    19→
    20→    // Simple deterministic data generation for consistent benchmarks
    21→    for i in 0..n_obs {
    22→        // Intercept column
    23→        x_data.push(1.0);
    24→
    25→        // Generate predictors
    26→        for j in 1..n_vars {
    27→            x_data.push((i as f64 + j as f64) * 0.1);
    28→        }
    29→
    30→        // Generate response (linear combination + small noise)
    31→        let y = 1.0
    32→            + (0..n_vars - 1)
    33→                .map(|j| (i as f64 + j as f64) * 0.1 * 0.5)
    34→                .sum::<f64>()
    35→            + (i as f64 * 0.01).sin() * 0.1;
    36→        y_data.push(y);
    37→    }
    38→
    39→    (x_data, y_data)
    40→}
    41→
    42→/// Create CSV file for R benchmarking
    43→fn create_r_data_file(x_data: &[f64], y_data: &[f64], n_obs: usize, n_vars: usize) -> String {
    44→    let timestamp = SystemTime::now()
    45→        .duration_since(UNIX_EPOCH)
    46→        .unwrap()
    47→        .as_nanos();
    48→    let filename = format!("/tmp/r_bench_data_{}_{}.csv", std::process::id(), timestamp);
    49→
    50→    let mut file = File::create(&filename).expect("Failed to create CSV file");
    51→
    52→    // Write header
    53→    write!(file, "y").unwrap();
    54→    for i in 1..n_vars {
    55→        write!(file, ",x{}", i).unwrap();
    56→    }
    57→    writeln!(file).unwrap();
    58→
    59→    // Write data
    60→    for i in 0..n_obs {
    61→        write!(file, "{}", y_data[i]).unwrap();
    62→        for j in 1..n_vars {
    63→            write!(file, ",{}", x_data[i * n_vars + j]).unwrap();
    64→        }
    65→        writeln!(file).unwrap();
    66→    }
    67→
    68→    filename
    69→}
    70→
    71→/// Benchmark R's lm() function (simplified version)
    72→fn benchmark_r_lm(data_file: &str, n_vars: usize) -> f64 {
    73→    // Create formula string
    74→    let mut formula = "y ~ ".to_string();
    75→    for i in 1..n_vars {
    76→        if i > 1 {
    77→            formula.push_str(" + ");
    78→        }
    79→        formula.push_str(&format!("x{}", i));
    80→    }
    81→
